-- ═══════════════════════════════════════════════════════════════════════
-- CARGA INICIAL desde planillas Excel 2026
-- 363 filas: 157 Alcorta + 157 Unicenter + 49 Oficina (2026-01-02 → 2026-06-08)
-- ═══════════════════════════════════════════════════════════════════════
ON CONFLICT (local, fecha) DO UPDATE SET
  efectivo = EXCLUDED.efectivo,
  tarjeta = EXCLUDED.tarjeta,
  qr = EXCLUDED.qr,
  vales = EXCLUDED.vales,
  cant_transacciones = EXCLUDED.cant_transacciones,
  online = EXCLUDED.online,
  fc_oficina = EXCLUDED.fc_oficina,
  controlado = EXCLUDED.controlado,
  actualizado_at = NOW();

-- Verificación
SELECT local, COUNT(*) AS filas, MIN(fecha) AS desde, MAX(fecha) AS hasta, ROUND(SUM(efectivo+tarjeta+qr+vales+online+fc_oficina)) AS total_cargado
FROM ventas_diarias GROUP BY local ORDER BY local;
